mapper.select:
select *
from logistics_carrier_connection
where 1 = 1

    and carrier_account_id = #{carrierAccountId}


    and provider_kind = #{providerKind}


    and connection_name like concat('%', #{carrierName}, '%')


    and status = #{status}

order by display_order asc, create_time desc, carrier_account_id desc

mapper.insert:
insert into logistics_carrier_connection(
    connection_code, provider_kind, connection_name, api_base_url, status, credential_status,
    display_order, create_by, create_time, remark
) values (
    #{connectionCode}, #{providerKind}, #{carrierName}, #{apiBaseUrl}, #{status}, #{credentialStatus},
    #{displayOrder}, #{createBy}, sysdate(), #{remark}
)

mapper.update:
update logistics_carrier_channel_candidate
set status = 'MISSING',
    update_time = sysdate()
where carrier_account_id = #{carrierAccountId}
  and sync_batch_id <> #{syncBatchId}

mapper.select:
select *
from logistics_carrier_channel_candidate
where carrier_account_id = #{carrierAccountId}

    and status = #{status}

order by status asc, external_channel_name asc, external_channel_code asc

select *
from logistics_carrier_channel_candidate
where carrier_account_id = #{carrierAccountId}
  and external_channel_code = #{externalChannelCode}
limit 1

select * from logistics_system_channel where 1 = 1
and system_channel_code like concat('%', #{systemChannelCode}, '%')
and system_channel_name like concat('%', #{systemChannelName}, '%')
and standard_carrier_code = #{standardCarrierCode}
and status = #{status}
order by display_order asc, system_channel_code asc

mapper.insert:
insert into logistics_system_channel(
    system_channel_code, system_channel_name, standard_carrier_code, status,
    display_order, create_by, create_time, remark
) values (
    #{systemChannelCode}, #{systemChannelName}, #{standardCarrierCode}, #{status},
    #{displayOrder}, #{createBy}, sysdate(), #{remark}
)

