insert into logistics_label_order(
    business_order_no, carrier_account_id, connection_code, provider_kind, system_channel_code, external_channel_code,
    provider_order_no, status, create_payload_json, provider_result_json,
    created_time, create_by, create_time, remark
) values (
    #{businessOrderNo}, #{carrierAccountId}, #{connectionCode}, #{providerKind}, #{systemChannelCode}, #{externalChannelCode},
    #{providerOrderNo}, #{status}, #{createPayloadJson}, #{providerResultJson},
    sysdate(), #{createBy}, sysdate(), #{remark}
)

mapper.select:
select *
from logistics_label_order
where carrier_account_id = #{carrierAccountId}
  and provider_order_no = #{providerOrderNo}
limit 1

select *
from logistics_label_order
where 1 = 1

    and business_order_no like concat('%', #{businessOrderNo}, '%')


    and carrier_account_id = #{carrierAccountId}


    and provider_order_no = #{providerOrderNo}


    and status = #{status}

order by create_time desc, label_order_id desc

